module top_module(
    input [3:0] data1,
    input [3:0] data2,
    input [1:0] op,
    input clk,         // Added clk input
    output reg [3:0] q
);reg [3:0] result_reg;
reg [3:0] stage2_out;

always @(*) begin
    case(op)
        2'b00: result_reg = data1 + data2;
        2'b01: result_reg = data1 - data2;
        2'b10: result_reg = data1 & data2;
        2'b11: result_reg = data1 | data2;
        default: result_reg = 4'b0000; // Added default case
    endcase
end

always @(posedge clk) begin
    stage2_out <= result_reg;
    q <= stage2_out;
end

endmodule
